    "s6s1p2s": "Online-PDF-Zusammenführungstools:",
    "s6s1m1": "✅ Kostenlose Nutzung",
    "s6s1m2": "✅ Keine Installation erforderlich",
    "s6s1m3": "✅ Funktioniert auf jeder Plattform",
